// Pega o texto extraído do PDF
let texto = $json["text"];
let nome = $('Download file').first().json.name
// Remove linhas inúteis
texto = texto
  .split('\n')
  .filter(linha => 
    linha.trim() !== '' && 
    !linha.includes('ReportLab') && 
    !linha.includes('anonymous') && 
    !linha.includes('unspecified') && 
    !linha.match(/D:\d+/) && 
    !linha.match(/^\d+\.\d+/)
  )
  .join('\n');

// Retorna o texto limpo
return [{ texto_limpo: texto, nome_arquivo: nome  }];

